@ls: bcfexa-remote
@grep: bcfexa-remote:package.json|index.html|server.js
@bash: bcfexa-remote:dir /b | findstr package.json || findstr index.html || findstr server.js || echo No common web starters found
@bash: bcfexa-remote:python -m http.server 8000
@bash: echo "Access at http://localhost:8000"

@ls: bcfexa-remote
@grep: bcfexa-remote:package.json
@read: bcfexa-remote/package.json
@bash: bcfexa-remote:node --version && npm --version
@bash: bcfexa-remote:npm install
@bash: bcfexa-remote:npm start
@bash: echo "If Node server, check console for URL; else, try Python again"

@ls: bcfexa-remote
@grep: bcfexa-remote:scripts|start|dev
@bash: bcfexa-remote:tasklist | findstr node || echo No Node process running
@bash: bcfexa-remote:npm run build 2>&1 || echo Build failed
@bash: bcfexa-remote:npm start 2>&1
@bash: echo "Check output above; if started, access at http://localhost:3000 or as per console"

@ls: bcfexa-remote
@find: bcfexa-remote:package.json,server.js,app.js,index.js,*.config.js
@read: bcfexa-remote/package.json
@bash: bcfexa-remote:netstat -ano | findstr :3000 && netstat -ano | findstr :8000 && netstat -ano | findstr :8080
@bash: bcfexa-remote:tasklist | findstr /i node
@bash: bcfexa-remote:npm run dev 2>&1 || npm start 2>&1 || node server.js 2>&1 || echo "No auto-start found; check scripts"

@ls: bcfexa-remote
@find: bcfexa-remote:package.json,*.json,server.*,app.*,index.*,config.*
@read: bcfexa-remote/package.json
@bash: bcfexa-remote:dir /b
@bash: bcfexa-remote:netstat -ano | findstr LISTENING
@bash: bcfexa-remote:tasklist | findstr /i node
@bash: bcfexa-remote:tasklist | findstr /i python

@read: bcfexa-remote/package.json
@read: bcfexa-remote/server.js
@bash: bcfexa-remote:type package.json | findstr "scripts\|main\|port"
